import { countryOptions, regionOptions } from '@constants';
import { doesCountryRequireState } from '@domain/constants/countriesRequiringState';
import { PublicActionPage } from '@domain/publicActionPage';
import {
  useGetIsFreeTickets,
  useTotalAmount,
} from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks';
import { useEffect, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { CountryValues } from 'src/domain/constants/countryOptions';
import { useTicketTotalAmount } from '../../ActionPageView/ActionPageLayout/ActionPageBody/hooks';
import { getFieldNames } from '../AddressControl/getFieldNames';
import { FormInputControl } from '../FormInputControl';
import { FormSelectControl } from '../SelectControl';
import { FormSmartyAddressInput } from '../SmartyAddressInput/FormSmartyAddressInput';
import { SmartyAddressInputProps } from '../SmartyAddressInput/SmartyAddressInput';
import { getPostalCodeLabel, getRegionLabel } from './helpers';

export type FormAddressInputsProps = Pick<SmartyAddressInputProps, 'label' | 'variant'> & {
  actionPage?: PublicActionPage;
  allowedCountries?: CountryValues[];
  fieldPrefix: string | undefined;
  fieldPrefixDelimiter: string | undefined;
  isRequired?: boolean | undefined;
  showAllInputs?: boolean;
  showCountrySelect?: boolean;
  showLine2?: boolean;
};

export const FormAddressInputs = ({
  actionPage,
  allowedCountries,
  fieldPrefix,
  fieldPrefixDelimiter,
  isRequired,
  label,
  showAllInputs = true,
  showCountrySelect = true,
  showLine2 = true,
  variant,
}: FormAddressInputsProps) => {
  const { t } = useTranslation('formControls');
  const { formState, getValues, setValue, trigger, watch } = useFormContext();
  const eventTicketsAttributes = watch('eventTicketsAttributes');
  const donationAmount = useTotalAmount();
  const ticketAmount = useTicketTotalAmount(actionPage);
  const totalAmount = donationAmount + ticketAmount;
  const isEmployerAddress = typeof label === 'string' && label.toLowerCase().includes('employer');
  const isFreeTickets = useGetIsFreeTickets(actionPage);
  const isInitialState = totalAmount === 0 && (eventTicketsAttributes?.length ?? 0) === 0;
  const line1 = watch('addressAttributes.line1');
  const allowedCountryOptions = useMemo(() => {
    return allowedCountries
      ? countryOptions.filter(({ value }) => allowedCountries.includes(value))
      : countryOptions;
  }, [allowedCountries]);

  const { fieldCity, fieldCountry, fieldLine2, fieldPostalCode, fieldRegion } = getFieldNames(
    fieldPrefix,
    fieldPrefixDelimiter
  );

  const country = watch(fieldCountry);
  const region = watch(fieldRegion);

  const isRegionRequired = useMemo(() => {
    return isRequired && doesCountryRequireState(country);
  }, [isRequired, country]);

  const countryRegions = useMemo(() => {
    if (country) {
      return regionOptions[country.toLowerCase()] ?? [];
    } else {
      return [];
    }
  }, [country]);

  useEffect(() => {
    if (allowedCountryOptions?.length === 1 && !getValues(fieldCountry)) {
      setValue(fieldCountry, allowedCountryOptions[0]?.value);
    }

    // run once on mount
  }, []);

  useEffect(() => {
    // Revalidate address fields when toggling between paid and free tickets
    if (!formState.isValid && !isInitialState && line1) {
      trigger('addressAttributes');
      trigger('cardZip');
    }
  }, [line1, formState.isValid, isInitialState, trigger]);

  // Handle conditional region validation when country changes
  useEffect(() => {
    if (country && region) {
      trigger(fieldRegion);
    }
  }, [country, region, trigger, fieldRegion]);

  // Don't display or require donor address for free tickets.
  // Don't display donor address on initial load.
  // Always display employer address fields.
  if (!isEmployerAddress && ((isFreeTickets && donationAmount === 0) || isInitialState)) {
    return null;
  }

  return (
    <>
      <div className="flex w-full items-stretch gap-2">
        <FormSmartyAddressInput
          actionPage={actionPage}
          fieldPrefix={fieldPrefix}
          fieldPrefixDelimiter={fieldPrefixDelimiter}
          isRequired={isRequired}
          label={label}
          variant={variant}
        />
        {showAllInputs && showLine2 && (
          <FormInputControl
            autoComplete="address-line2"
            label={t('formAddressControl.line2')}
            name={fieldLine2}
            placeholder="Suite 1770"
          />
        )}
      </div>
      {showAllInputs && (
        <div
          className="grid grid-rows-2 gap-2 gap-y-0"
          style={{
            gridTemplateColumns: 'repeat(3, 1fr)',
            gridTemplateRows: '1fr',
          }}
        >
          <FormInputControl
            autoComplete="address-level2"
            formControlProps={{ className: 'w-full' }}
            inputGroupProps={{
              style: {
                gridColumnEnd: { base: 3, md: 2 },
                gridColumnStart: 1,
              },
            }}
            isRequired={isRequired}
            label={t('formAddressControl.city')}
            name={fieldCity}
            placeholder="New Orleans"
          />
          {!countryRegions.length ? (
            <FormInputControl
              autoComplete="address-level1"
              isRequired={isRegionRequired}
              label={getRegionLabel(country, t)}
              name={fieldRegion}
              placeholder="LA"
            />
          ) : (
            <FormSelectControl
              autoComplete="address-level1"
              isRequired={isRegionRequired}
              label={getRegionLabel(country, t)}
              name={fieldRegion}
              options={countryRegions}
              placeholder="-"
            />
          )}
          <FormInputControl
            autoComplete="postal-code"
            isRequired={isRequired}
            label={getPostalCodeLabel(country, t)}
            name={fieldPostalCode}
            placeholder="70112"
          />
        </div>
      )}
      {showAllInputs && showCountrySelect ? (
        <FormSelectControl
          autoComplete="country"
          isRequired={isRequired}
          label={t('formAddressControl.country')}
          name={fieldCountry}
          options={allowedCountryOptions}
          placeholder="-"
        />
      ) : null}
    </>
  );
};

